import React from 'react'
import { DialogOverlay, DialogOverlayFooter, DialogOverlayActions, Button, Paragraph } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'

export default function OptInOverlay({ overlay, onEnable }) {
  const { t } = useTranslation()

  return (
    <DialogOverlay {...overlay} title={t('relation-view.opt-in', 'Enable Relationship Viewing')}>
      <Paragraph>
        {t(
          'relation-view.explanation-1',
          'You agree to allow other users to see their relationship to you, your portrait in Family Tree, if available, and any shared ancestors.'
        )}
      </Paragraph>
      <Paragraph>
        <em>
          {t(
            'relation-view.explanation-2',
            'Both you and the other user must have Relationship Viewing enabled to see how you are related.'
          )}
        </em>
      </Paragraph>
      <Paragraph>
        {t('relation-view.explanation-3', 'You can disable this feature in your Contact Settings.')}
      </Paragraph>
      <Link to="https://www.familysearch.org/help/helpcenter/article/how-do-i-turn-on-or-off-the-option-to-view-my-relationship-to-other-users">
        {t('common-ui:learn-more.action', 'Learn More')}
      </Link>

      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button onClick={overlay.close}>{t('common-ui:cancel.action')}</Button>
          <Button
            onClick={(event) => {
              overlay.close(event)
              onEnable?.(event)
            }}
            emphasis="high"
          >
            {t('relation-view.enable', 'Enable')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
